import{_ as e,o as a,c as p,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"初星系列消耗品","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/9.消耗品/6.系列消耗品/初星系列消耗品.md","filePath":"4.资源分区/7.物品与装备/9.消耗品/6.系列消耗品/初星系列消耗品.md"}'),s={name:"4.资源分区/7.物品与装备/9.消耗品/6.系列消耗品/初星系列消耗品.md"};function o(d,b,_,l,i,c){return a(),p("div",null,[...b[0]||(b[0]=[r("h1",{id:"初星系列消耗品",tabindex:"-1"},[t("初星系列消耗品 "),r("a",{class:"header-anchor",href:"#初星系列消耗品","aria-label":'Permalink to "初星系列消耗品"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风023元旦版")])])],-1),n('<h1 id="初星系列消耗品-1" tabindex="-1">初星系列消耗品 <a class="header-anchor" href="#初星系列消耗品-1" aria-label="Permalink to &quot;初星系列消耗品&quot;">​</a></h1><p>初星消耗品<br> 该系列下属所有物品均是主神提供的版本，因此视为【消耗品-药物】。使用次数将被单独标记在类型后，不具有副作用，只存在药物疲劳。<br> 在持续时间结束后，这些消耗品提供的持续性效果也会消失。<br> 【该系列消耗品的词缀请参考偶像称号中的专有词条，其中解释了不同词缀的具体效果。】</p><p>初星水<br> 类型：消耗品（3）<br> 价格：500<br> 持续：3+传奇风度*1轮<br> 描述：初星学园提供的廉价蓝色瓶装矿泉水。虽然其貌不扬，但只要饮用就能临时提高表达能力，性价比高。<br> 效果：持续时间内，你在表达相关检定上获得3DP表现加值。</p><p>鲜果醋<br> 类型：消耗品（1）<br> 价格：500<br> 持续：3+传奇风度*1轮<br> 描述：开口处有吸管，多种水果混合的橙色半透明状饮料，可以临时提高表达能力，恢复体力。<br> 效果：持续时间内，你在表达相关检定上获得3DP表现加值，同时获得1点疲乏不良点数恢复能力，医疗点数24点。</p><p>乌龙茶<br> 类型：消耗品（1）<br> 价格：500<br> 持续：3+传奇风度*1轮<br> 描述：深棕色瓶装液体，只要饮用就可以在短时间内增加元气，但跳舞的时候不适合喝的太多。<br> 效果：持续时间内，你获得【元气2】。</p><p>热咖啡<br> 类型：消耗品（1）<br> 价格：500<br> 持续：3+传奇风度*1轮<br> 效果：深褐色咖啡，热气腾腾，饮用的话就能增加干劲。<br> 效果：持续时间内，你获得【干劲1】。</p><p>混合冰沙<br> 类型：消耗品（1）<br> 价格：500<br> 持续：3+传奇风度*1轮<br> 描述：橙色饮品，饮用的话可以重振自信，让你再来一次！<br> 效果：持续时间内，你可以将自身的表达技能相关检定进行重骰，但必须接受重骰结果，该效果每轮只能生效一次。</p><p>维生素饮料<br> 类型：消耗品（1）<br> 价格：500<br> 持续：3+传奇风度*1轮<br> 描述：胡萝卜色瓶装液体，其中充满了维生素，只要饮用就可以进入好调状态。<br> 效果：持续时间内，你获得【好调】状态。</p><p>冰咖啡<br> 类型：消耗品（1）<br> 价格：1000<br> 持续：3+传奇风度*1轮<br> 描述：崭新出炉的冰咖啡，虽然味道很苦，但可以刺激大脑，临时提升集中能力。<br> 效果：持续时间内，你获得【集中2】。</p><p>路易波士茶<br> 类型：消耗品（3）<br> 价格：1000<br> 持续：3+传奇风度*1轮<br> 描述：温暖的红色液体，只要喝下气质就会变得柔和，给人带来好印象。<br> 效果：持续时间内，你获得【好印象1】</p><p>体力爆发饮料<br> 类型：消耗品（3）<br> 价格：D+500<br> 持续：3+传奇风度*1轮<br> 描述：爆炸喷吐包装汽水，除了能让你进入绝好调状态外，还可以提供临时的元气。<br> 效果：持续时间内，你获得【元气3】；你获得【绝好调】状态。</p><p>时尚香草茶<br> 类型：消耗品（1）<br> 价格：D+500<br> 持续：3+传奇风度*1轮<br> 描述：橙黄色茶叶，热气腾腾，中间有四叶草，可以临时增加元气，也可以根据好印象增幅造成的伤害。<br> 效果：你获得【元气2】；你每具有1点好印象，则可以在攻击中额外造成1点同类型伤害，因此增加的同类型伤害最多为【传奇风度*2】点。</p><p>初星乳清蛋白<br> 类型：消耗品（3）<br> 价格：D+500<br> 持续：3+传奇风度*1轮<br> 描述：蓝色包装饮品，可以让你在短时间内多次行动。<br> 效果：持续时间内，每轮你额外获得1个只能进行基础移动行为的移动动作；当你使用花招动作服用该系列药物时，改为无需使用动作，每轮最多只能生效两次。</p><p>精选初星调配<br> 类型：消耗品（3）<br> 价格：D+500<br> 持续：3+传奇风度*1轮<br> 描述：多种饮品混合液体，配备在茶杯中，饮用的行为可以激励你的决心，每回合干劲提升。<br> 效果：持续时间内，每回合开始时你获得【干劲1】。</p><p>精选初星咖啡<br> 类型：消耗品（3）<br> 价格：D+1000<br> 持续：5轮<br> 描述：看起来更像是奶茶，每回合结束时，使集中增加，同时赋予提升表达能力的性能。<br> 效果：持续时间内，每轮开始时你获得【集中1】，与等同该消耗品提供集中数值的表达相关检定加值，类型为表现加值。</p><p>焙茶<br> 类型：消耗品（3）<br> 价格：C+1000<br> 持续：3+传奇风度*1轮<br> 描述：黄色饮品，只要饮用就可以进入温存状态，大幅度保存自身体力。<br> 效果：持续时间内，你获得【温存】状态。</p><p>姜汁汽水<br> 类型：消耗品（3）<br> 价格：C+1000<br> 持续：3+传奇风度*1轮<br> 描述：绿色汽水，只要饮用就可以进入坚决状态，以消耗提升为代价，大幅度增加造成的伤害。<br> 效果：持续时间内，你在表达相关检定上获得6DP表现加值，以及额外4个附加成功；你获得【坚决】状态。</p><p>初星超级苏打水<br> 类型：消耗品（3）<br> 价格：C+1000<br> 持续：3+传奇风度*1轮<br> 描述：淡蓝色气泡苏打水，只要饮用就可以进入坚决状态，以精神消耗提升为代价，还可以减轻体力损失。<br> 效果：持续时间内，你获得等同自身【传奇风度】+1点全伤害吸收能力；你获得【坚决】状态。</p><p>初星增幅能量<br> 类型：消耗品（3）<br> 价格：C+1000<br> 持续：3+传奇风度*1轮<br> 描述：配有闪电图案的紫色汽水，除了可以让你进入绝好调状态外，还可以加速行动能力。<br> 效果：持续时间内，你获得【绝好调】状态；每轮开始时，你额外获得一个只能进行基础移动的移动动作，同时可以对表达相关检定进行一次重骰，必须接受重骰结果，每轮只能使用该效果重骰一次。</p><p>精选初星茶<br> 类型：消耗品（3）<br> 价格：C+1000<br> 持续：3+传奇风度*1轮<br> 描述：闻起来很香，看起来像是红茶饮品，配有十分精致的一次性茶杯，可以持续增加好印象。<br> 效果：持续时间内，你获得等同自身【传奇风度】+1点【好印象】。</p><p>精选初星奶茶<br> 类型：消耗品（3）<br> 价格：C+1000<br> 持续：3+传奇风度*1轮<br> 描述：黄色茶杯配奶昔，只要饮用立刻就能进入全力状态，力量百分百！<br> 效果：持续时间内，你获得【全力】状态；你进行的表达相关检定加骰提升2级（上限8加骰）。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',23)])])}const D=e(s,[["render",o]]);export{f as __pageData,D as default};
